// frontend/src/components/vouchers/MyVouchers.js
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../../services/api';
import './Voucher.css';

// Example voucher card rendering in your component
const renderVoucherCard = (voucher) => {
    // Determine card type class based on face value
    const cardType = voucher.face_value >= 1000 ? 'premium' : 
                    voucher.face_value >= 500 ? 'standard' : 'small';

    return (
        <div key={voucher.id} className={`voucher-card ${cardType}`}>
            {/* Status Badge */}
            <div className={`voucher-status status-${voucher.current_status}`}>
                {voucher.current_status === 'active' ? '✅ Active' :
                 voucher.current_status === 'partially_used' ? '⚡ Partially Used' :
                 voucher.current_status === 'used' ? '💫 Used' : '⏰ Expired'}
            </div>

            {/* Card Header */}
            <div className="voucher-header">
                <div className="voucher-title">
                    <span>{voucher.template_name || 'Voucher'}</span>
                    <span className="voucher-type-badge">
                        R {voucher.face_value}
                    </span>
                </div>

                {/* Voucher Code */}
                <div className="voucher-code-display">
                    <div className="voucher-code-label">Voucher Number</div>
                    <div className="voucher-code-value">{voucher.voucher_code}</div>
                </div>

                {/* PIN Display */}
                <div className="voucher-pin">
                    <span className="voucher-pin-label">
                        🔐 PIN Code
                    </span>
                    <span className="voucher-pin-value">{voucher.pin_code}</span>
                </div>
            </div>

            {/* Card Body */}
            <div className="voucher-body">
                {/* Balance */}
                <div className="voucher-balance">
                    <span className="voucher-balance-label">Current Balance</span>
                    <span className="voucher-balance-amount">
                        R {voucher.current_balance}
                    </span>
                </div>

                {/* Details Grid */}
                <div className="voucher-details-grid">
                    <div className="voucher-detail-item">
                        <span className="voucher-detail-label">Face Value</span>
                        <span className="voucher-detail-value">R {voucher.face_value}</span>
                    </div>
                    <div className="voucher-detail-item">
                        <span className="voucher-detail-label">Expires</span>
                        <span className="voucher-detail-value">
                            {new Date(voucher.expires_at).toLocaleDateString()}
                        </span>
                    </div>
                </div>
            </div>

            {/* Card Footer - Actions */}
            {voucher.current_status === 'active' && voucher.current_balance > 0 && (
                <div className="voucher-footer">
                    <button 
                        className="btn-use"
                        onClick={() => handleUseVoucher(voucher)}
                    >
                        💳 Use for Payment
                    </button>
                    <button 
                        className="btn-claim"
                        onClick={() => handleClaimVoucher(voucher)}
                    >
                        💰 Claim Cash
                    </button>
                </div>
            )}

            {voucher.current_status !== 'active' && (
                <div className="voucher-footer">
                    <button 
                        className="btn-history"
                        onClick={() => viewVoucherHistory(voucher)}
                    >
                        📜 View History
                    </button>
                </div>
            )}
        </div>
    );
};

export default MyVouchers;
